class Node {
    boolean val;
    boolean isLeaf;
    Node topLeft;
    Node topRight;
    Node bottomLeft;
    Node bottomRight;

    public Node() {
        this(false, false, null, null, null, null);
    }

    public Node(boolean val, boolean isLeaf) {
        this(val, isLeaf, null, null, null, null);
    }

    public Node(boolean val, boolean isLeaf, Node topLeft, Node topRight, Node bottomLeft, Node bottomRight) {
        this.val = val;
        this.isLeaf = isLeaf;
        this.topLeft = topLeft;
        this.topRight = topRight;
        this.bottomLeft = bottomLeft;
        this.bottomRight = bottomRight;
    }
}

public Node construct(int[][] grid) {
    return helper(grid, 0, 0, grid.length);
}

private Node helper(int[][] grid, int x, int y, int length) {
    if (length == 1) {
        return new Node(grid[x][y] == 1, true);
    }

    Node tl = helper(grid, x, y, length / 2);
    Node tr = helper(grid, x, y + length / 2, length / 2);
    Node bl = helper(grid, x + length / 2, y, length / 2);
    Node br = helper(grid, x + length / 2, y + length / 2, length / 2);

    if (tl.isLeaf && tr.isLeaf && bl.isLeaf && br.isLeaf &&
        tl.val == tr.val && tr.val == bl.val && bl.val == br.val) {
        return new Node(tl.val, true);
    } else {
        return new Node(false, false, tl, tr, bl, br);
    }
}
